        return edges;
      }

      @Override
      public Set<E> edgeValueOrDefault(Object nodeA, Object nodeB, Set<E> defaultValue) {
        Set<E> edges = edgesConnecting(nodeA, nodeB);
        return edges.isEmpty() ? defaultValue : edges;
      }
    };
